/* com.educare.edu.comn.mapper.AjaxMapper.selectLctreList */ SELECT L.* FROM t_lecture L WHERE 1 = 1
AND (L.EDU_NM LIKE CONCAT('%',#{srchWrd},'%') OR L.INSTRCTR_NM LIKE CONCAT('%',#{srchWrd},'%') OR L.EDU_CTGRY_NM LIKE CONCAT('%',#{srchWrd},'%') OR L.DETAIL_CTGRY_NM LIKE CONCAT('%',#{srchWrd},'%') )
AND L.INSTRCTR_NM = #{userNm}
ORDER BY L.EDU_PERIOD_BEGIN DESC
LIMIT 0,0

/* com.educare.edu.comn.mapper.AjaxMapper.selectLctreListCnt */ SELECT COUNT(L.EDU_SEQ) FROM t_lecture L WHERE 1=1
AND (L.EDU_NM LIKE CONCAT('%',#{srchWrd},'%') OR L.INSTRCTR_NM LIKE CONCAT('%',#{srchWrd},'%') OR L.EDU_CTGRY_NM LIKE CONCAT('%',#{srchWrd},'%') OR L.DETAIL_CTGRY_NM LIKE CONCAT('%',#{srchWrd},'%') )
AND L.INSTRCTR_NM = #{userNm}
LIMIT 0,0

/* com.educare.edu.comn.mapper.AjaxMapper.selectFeedbackList */ SELECT A.* , (SELECT COUNT(*) FROM t_feedback_question WHERE FB_IDX=A.IDX AND QT_TYPE=0 ) AS QT_TYPE0_CNT , (SELECT COUNT(*) FROM t_feedback_question WHERE FB_IDX=A.IDX AND QT_TYPE in (1,2,3) ) AS QT_TYPE1_CNT FROM t_feedback A WHERE 1=1
AND A.TITLE LIKE CONCAT('%',#{eduVo.srchWrd},'%') OR A.REG_NM LIKE CONCAT('%',#{eduVo.srchWrd},'%')
AND A.ORG_CD = #{vo.orgCd} ORDER BY A.REG_TIME DESC

/* com.educare.edu.comn.mapper.AjaxMapper.selectPassCertList  */
	SELECT a.* 
	FROM t_pass_cert_tpl AS a
	WHERE 1=1 

			AND a.TITLE LIKE CONCAT('%',#{srchWrd},'%') 
			OR a.ORG_NM LIKe CONCAT('%',#{srchWrd},'%') 


			and a.pass_tp = #{passTp}

	ORDER BY a.PASS_IDX DESC;

/* com.educare.edu.comn.mapper.AjaxMapper.selectOneByPassIdx  */
	SELECT TITLE 
	FROM t_pass_cert_tpl 
	WHERE PASS_IDX = #{i}

mapper.update:
/* com.educare.edu.comn.mapper.AjaxMapper.updateLectureStdntMeal  */
update t_lecture_stdnt
set meal_fee = #{mealFee}
where edu_seq = #{eduSeq}

and user_id = #{userId}

/* com.educare.edu.comn.mapper.AjaxMapper.updateLectureStdntDormi  */
update t_lecture_stdnt
set dormi_fee = #{dormiFee}
where edu_seq = #{eduSeq}

and user_id = #{userId}

/* com.educare.edu.comn.mapper.AjaxMapper.updateLectureStdntDeposit  */
update t_lecture_stdnt
set deposit_yn = #{depositYn}
where edu_seq = #{eduSeq}

and user_id = #{userId}
